adminDeliveryProfileCreate.query:
mutation DeliveryProfileLifecycleCreate($profile: DeliveryProfileInput!) {
  deliveryProfileCreate(profile: $profile) {
    profile {
      id
      name
      version
      originLocationCount
      zoneCountryCount
      activeMethodDefinitionsCount
      profileItems(first: 5) {
        nodes {
          product {
            id
            title
          }
          variants(first: 5) {
            nodes {
              id
              title
            }
          }
        }
      }
      profileLocationGroups {
        countriesInAnyZone {
          zone
          country {
            code {
              countryCode
              restOfWorld
            }
          }
        }
        locationGroup {
          id
        }
        locationGroupZones(first: 5) {
          nodes {
            zone {
              id
              name
              countries {
                code {
                  countryCode
                  restOfWorld
                }
              }
            }
            methodDefinitions(first: 5) {
              nodes {
                id
                name
                active
                description
                rateProvider {
                  ... on DeliveryRateDefinition {
                    id
                    price {
                      amount
                      currencyCode
                    }
                  }
                }
                methodConditions {
                  id
                  field
                  operator
                  conditionCriteria {
                    __typename
                    ... on Weight {
                      value
                      unit
                    }
                    ... on MoneyV2 {
                      amount
                      currencyCode
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
    userErrors {
      field
      message
    }
  }
}

